// src/sidecar/notify.ts
var broadcast = () => {};
function setNotifyBroadcast(fn) {
  broadcast = fn;
}
function notifyIfUnfocused(title, body) {
  if (!settingsStore.get().notifications)
    return;
  broadcast("notify", { title, body: body.slice(0, 140) });
}

// src/sidecar/approvals.ts
var broadcast2 = () => {};
function setApprovalBroadcast(fn) {
  broadcast2 = fn;
}
var pending = new Map;
var approvals = {
  request(tabId, toolName, input, ctx) {
    const requestId = randomUUID();
    return new Promise((resolve) => {
      pending.set(requestId, { resolve, tabId, input });
      ctx.signal?.addEventListener("abort", () => {
        if (pending.delete(requestId)) {
          broadcast2("approval:cancelled", { requestId });
          resolve({ behavior: "deny", message: "Cancelled by interrupt" });
        }
      });
      console.log(`[approvals] prompt for ${toolName} (${requestId})`);
      broadcast2("session:status", { tabId, status: "awaitingApproval" });
      try {
        notifyIfUnfocused("Claude needs approval", ctx.title ?? `Wants to use ${toolName}`);
      } catch (err) {
        console.error("[approvals] notification failed:", err);
      }
      broadcast2("approval:request", {
        requestId,
        tabId,
        toolUseId: ctx.toolUseID ?? "",
        toolName,
        input,
        promptText: ctx.title,
        decisionReason: ctx.decisionReason
      });
    });
  },
  respond(requestId, result) {
    const entry = pending.get(requestId);
    if (!entry)
      return;
    pending.delete(requestId);
    broadcast2("session:status", { tabId: entry.tabId, status: "streaming" });
    if (result.behavior === "allow") {
      entry.resolve({ behavior: "allow", updatedInput: result.updatedInput ?? entry.input });
    } else {
      entry.resolve(result);
    }
  },
  cancelAll(tabId) {
    for (const [id, entry] of pending) {
      if (entry.tabId === tabId) {
        pending.delete(id);
        broadcast2("approval:cancelled", { requestId: id });
        entry.resolve({ behavior: "deny", message: "Session closed" });
      }
    }
  }
};

// src/sidecar/auth.ts
import { spawn } from "child_process";
import { existsSync as existsSync2 } from "fs";
import { homedir as homedir2 } from "os";
