// src/sidecar/desktop-mcp.ts
import { existsSync as existsSync4, readdirSync as readdirSync2, readFileSync as readFileSync4 } from "fs";
import { join as join10 } from "path";
var claudeDir = () => join10(appDataDir(), "Claude");
function readJson(path) {
  try {
    return JSON.parse(readFileSync4(path, "utf8"));
  } catch {
    return null;
  }
}
function substitute(value, dir, userConfig) {
  let missing = false;
  const result = value.replaceAll("${__dirname}", dir).replace(/\$\{user_config\.([^}]+)\}/g, (_4, key) => {
    const v7 = userConfig[key];
    if (v7 === undefined || v7 === null || v7 === "") {
      missing = true;
      return "";
    }
    return Array.isArray(v7) ? v7.join(",") : String(v7);
  });
  return missing ? null : result;
}
function loadConfigServers(statuses) {
  const result = {};
  const config = readJson(join10(claudeDir(), "claude_desktop_config.json"));
  for (const [name, server] of Object.entries(config?.mcpServers ?? {})) {
    if (!server?.command) {
      statuses.push({ name, source: "config", imported: false, note: "not a local server" });
      continue;
    }
    result[name] = {
      type: "stdio",
      command: server.command,
      ...server.args ? { args: server.args } : {},
      ...server.env ? { env: server.env } : {}
    };
    statuses.push({ name, source: "config", imported: true });
  }
  return result;
}
function loadExtensionServers(statuses) {
  const result = {};
  const extRoot = join10(claudeDir(), "Claude Extensions");
  const settingsRoot = join10(claudeDir(), "Claude Extensions Settings");
  if (!existsSync4(extRoot))
    return result;
  for (const id2 of readdirSync2(extRoot)) {
    const dir = join10(extRoot, id2);
    const manifest = readJson(join10(dir, "manifest.json"));
    if (!manifest)
      continue;
    const name = manifest.display_name || manifest.name || id2;
    const push = (imported, note) => {
      statuses.push({ name, source: "extension", imported, note });
    };
    const settings = readJson(join10(settingsRoot, `${id2}.json`));
    if (settings?.isEnabled === false) {
      push(false, "disabled in Claude Desktop");
      continue;
    }
    const mcp = manifest.server?.mcp_config;
    if (!mcp?.command) {
      push(false, "no runnable server");
      continue;
    }
    const userConfig = {};
    for (const [key, spec] of Object.entries(manifest.user_config ?? {})) {
      const v7 = settings?.userConfig?.[key] ?? spec.default;
      if (v7 !== undefined && !(Array.isArray(v7) && v7.length === 0))
        userConfig[key] = v7;
    }
    const args = [];
    let unresolved = false;
    for (const raw of mcp.args ?? []) {
      const sub = substitute(raw, dir, userConfig);
      if (sub === null)
        unresolved = true;
      else
        args.push(sub);
    }
    const env = {};
    for (const [k3, raw] of Object.entries(mcp.env ?? {})) {
      const sub = substitute(raw, dir, userConfig);
      if (sub !== null)
        env[k3] = sub;
    }
    const requiredMissing = Object.entries(manifest.user_config ?? {}).some(([key, spec]) => spec.required && userConfig[key] === undefined);
    if (unresolved && requiredMissing) {
      push(false, "needs configuration in Claude Desktop");
      continue;
    }
    if (mcp.command === "uv" && args[0] === "run" && !args.includes("--directory")) {
      args.splice(1, 0, "--directory", dir);
    }
    result[name] = {
      type: "stdio",
      command: mcp.command,
      ...args.length ? { args } : {},
      ...Object.keys(env).length ? { env } : {}
    };
    push(true);
  }
  return result;
}
function loadDesktopMcpServers() {
  const statuses = [];
  return { ...loadExtensionServers(statuses), ...loadConfigServers(statuses) };
}
function listDesktopMcp() {
  const statuses = [];
  loadExtensionServers(statuses);
  loadConfigServers(statuses);
  return statuses;
}

