// src/sidecar/transcript-search.ts
import { readdir as readdir4, readFile as readFile7, stat as stat2 } from "fs/promises";
import { homedir as homedir7 } from "os";
import { join as join19 } from "path";
var projectsRoot = () => join19(homedir7(), ".claude", "projects");
var cache4 = new Map;
function extractText(content) {
  if (typeof content === "string")
    return content;
  if (!Array.isArray(content))
    return "";
  return content.map((block) => {
    if (block && typeof block === "object" && block.type === "text") {
      return block.text ?? "";
    }
    return "";
  }).filter(Boolean).join(`
`);
}
async function parseFile(path, mtimeMs) {
  const cached = cache4.get(path);
  if (cached && cached.mtimeMs === mtimeMs)
    return cached;
  const entry = { mtimeMs, texts: [] };
  try {
    const raw = await readFile7(path, "utf8");
    for (const line of raw.split(`
`)) {
      if (!line.trim())
        continue;
      try {
        const obj = JSON.parse(line);
        if (!entry.cwd && obj.cwd)
          entry.cwd = obj.cwd;
        if (obj.isMeta)
          continue;
        if (obj.type !== "user" && obj.type !== "assistant")
          continue;
        const text = extractText(obj.message?.content);
        if (!text.trim() || text.startsWith("<"))
          continue;
        entry.texts.push({ role: obj.type, text });
      } catch {}
    }
  } catch {}
  cache4.set(path, entry);
  return entry;
}
function snippetAround(text, index, needleLen) {
  const start = Math.max(0, index - 60);
  const end = Math.min(text.length, index + needleLen + 60);
  const clean = (s) => s.replace(/\s+/g, " ").trim();
  return (start > 0 ? "\u2026" : "") + clean(text.slice(start, end)) + (end < text.length ? "\u2026" : "");
}
var transcriptSearch = {
  async search(queryText, limit = 30) {
    const needle = queryText.trim().toLowerCase();
    if (needle.length < 2)
      return [];
    const root = projectsRoot();
    let projectDirs;
    try {
      projectDirs = (await readdir4(root, { withFileTypes: true })).filter((d) => d.isDirectory()).map((d) => join19(root, d.name));
    } catch {
      return [];
    }
    const files = [];
    for (const dir of projectDirs) {
      try {
        for (const f of await readdir4(dir)) {
          if (!f.endsWith(".jsonl"))
            continue;
          const path = join19(dir, f);
          const st2 = await stat2(path);
          files.push({ path, sessionId: f.slice(0, -6), mtimeMs: st2.mtimeMs });
        }
      } catch {}
    }
    files.sort((a, b) => b.mtimeMs - a.mtimeMs);
    const hits = [];
    for (const file5 of files) {
      if (hits.length >= limit)
        break;
      const entry = await parseFile(file5.path, file5.mtimeMs);
      for (const { role, text } of entry.texts) {
        const idx = text.toLowerCase().indexOf(needle);
        if (idx === -1)
          continue;
        hits.push({
          sessionId: file5.sessionId,
          cwd: entry.cwd,
          role,
          snippet: snippetAround(text, idx, needle.length),
          lastModified: file5.mtimeMs
        });
        break;
      }
    }
    return hits;
  },
  async exportMarkdown(sessionId) {
    const root = projectsRoot();
    let found = null;
    try {
      for (const d of await readdir4(root, { withFileTypes: true })) {
        if (!d.isDirectory())
          continue;
        const candidate = join19(root, d.name, `${sessionId}.jsonl`);
        try {
          await stat2(candidate);
          found = candidate;
          break;
        } catch {}
      }
    } catch {
      return null;
    }
    if (!found)
      return null;
    const lines = [];
    let cwd;
    const raw = await readFile7(found, "utf8");
    for (const line of raw.split(`
`)) {
      if (!line.trim())
        continue;
      try {
        const obj = JSON.parse(line);
        if (!cwd && obj.cwd)
          cwd = obj.cwd;
        if (obj.isMeta)
          continue;
        if (obj.type === "user") {
          const text = extractText(obj.message?.content);
          if (text.trim() && !text.startsWith("<"))
            lines.push(`## You

${text.trim()}`);
        } else if (obj.type === "assistant") {
          const content = obj.message?.content;
          const text = extractText(content);
          if (text.trim())
            lines.push(`## Claude

${text.trim()}`);
          if (Array.isArray(content)) {
            for (const block of content) {
              const b = block;
              if (b.type === "tool_use" && b.name) {
                const hint = b.input?.command ?? b.input?.file_path ?? b.input?.pattern ?? "";
                lines.push(`> \uD83D\uDD27 **${b.name}**${hint ? ` \u2014 \`${String(hint).slice(0, 120)}\`` : ""}`);
              }
            }
          }
        }
      } catch {}
    }
    const header = [
      `# Claude session ${sessionId}`,
      "",
      `*Exported from Seashell on ${new Date().toLocaleString()}${cwd ? ` \xB7 project: \`${cwd}\`` : ""}*`,
      ""
    ].join(`
`);
    return `${header}
${lines.join(`

`)}
`;
  }
};

// src/sidecar/worktrees.ts
import { execFile as execFile3 } from "child_process";
import { basename, dirname as dirname2, join as join20 } from "path";
import { promisify as promisify2 } from "util";
var run2 = promisify2(execFile3);
async function git2(cwd, ...args) {
  const { stdout } = await run2("git", ["-C", cwd, ...args], { windowsHide: true });
  return stdout.trim();
}
var worktrees = {
  async create(cwd) {
    try {
      const root = await git2(cwd, "rev-parse", "--show-toplevel");
      const name = `wt-${Date.now().toString(36)}`;
      const branch = `seashell/${name}`;
      const path = join20(dirname2(root), `${basename(root)}-${name}`);
      await git2(root, "worktree", "add", "-b", branch, path);
      return { path, branch };
    } catch (err) {
      return { error: err instanceof Error ? err.message : String(err) };
    }
  },
  async merge(worktreeCwd) {
    try {
      const branch = await git2(worktreeCwd, "rev-parse", "--abbrev-ref", "HEAD");
      const commonDir = await git2(worktreeCwd, "rev-parse", "--git-common-dir");
      const mainRoot = dirname2(commonDir.replace(/\//g, "\\"));
      if (await git2(worktreeCwd, "status", "--porcelain")) {
        await git2(worktreeCwd, "add", "-A");
        await git2(worktreeCwd, "commit", "-m", "Seashell worktree changes");
      }
      await git2(mainRoot, "merge", "--no-ff", branch, "-m", `Merge ${branch}`);
      await git2(mainRoot, "worktree", "remove", worktreeCwd, "--force");
      await git2(mainRoot, "branch", "-d", branch);
      return { ok: true };
    } catch (err) {
      return { error: err instanceof Error ? err.message : String(err) };
    }
  }
};

