// src/sidecar/index.ts
var secret = process.env.SIDECAR_SECRET ?? "";
var clients = new Set;
function broadcast5(channel, payload) {
  const msg = JSON.stringify({ event: channel, payload });
  for (const ws2 of clients)
    ws2.send(msg);
}
setBroadcast(broadcast5);
setApprovalBroadcast(broadcast5);
setAuthBroadcast(broadcast5);
setNotifyBroadcast(broadcast5);
injectStoredToken();
ensureRetrospectiveSkill();
var server = Bun.serve({
  hostname: "127.0.0.1",
  port: Number(process.env.SIDECAR_PORT ?? 0),
  fetch(req, srv) {
    const url = new URL(req.url);
    if (secret && url.searchParams.get("s") !== secret) {
      return new Response("forbidden", { status: 403 });
    }
    if (srv.upgrade(req))
      return;
    return new Response("seashell sidecar", { status: 200 });
  },
  websocket: {
    open(ws2) {
      clients.add(ws2);
      ws2.send(JSON.stringify({ event: "auth:state", payload: auth.getState() }));
    },
    close(ws2) {
      clients.delete(ws2);
    },
    async message(ws2, raw) {
      let req;
      try {
        req = JSON.parse(String(raw));
      } catch {
        return;
      }
      try {
        const handler = handlers[req.channel];
        if (!handler)
          throw new Error(`Unknown channel: ${req.channel}`);
        const result = await handler(req.arg);
        ws2.send(JSON.stringify({ id: req.id, result: result ?? null }));
      } catch (err) {
        ws2.send(JSON.stringify({ id: req.id, error: err instanceof Error ? err.message : String(err) }));
      }
    }
  }
});
console.log(`SIDECAR_PORT=${server.port}`);
function shutdown() {
  sessionManager.disposeAll();
  devserver.stopAll();
  usageStore.flush();
  process.exit(0);
}
process.on("SIGTERM", shutdown);
process.on("SIGINT", shutdown);
